36	function isPlainObject(v: unknown): v is Record<string, unknown> {
37	  return typeof v === "object" && v !== null && !Array.isArray(v);
38	}
39	
40	async function readJsonConfig(
41	  filePath: string,
42	): Promise<Record<string, unknown>> {
43	  let rawContent: string;
44	  try {
45	    rawContent = await readFile(filePath, "utf-8");
46	  } catch (err) {
47	    const code = (err as NodeJS.ErrnoException).code;
48	    if (code === "ENOENT")
49	      throw new Error(`Config file not found: ${filePath}`);
50	    throw err;
51	  }
52	  let parsed: unknown;
53	  try {
54	    parsed = JSON.parse(rawContent);
55	  } catch {
56	    throw new Error(`Config file is not valid JSON: ${filePath}`);
57	  }
58	  if (!isPlainObject(parsed)) {
59	    throw new Error(`Config file is not a JSON object: ${filePath}`);
60	  }
61	  return parsed;
62	}
63	
64	function computeUndoPatch(
65	  original: Record<string, unknown>,
66	  patch: Record<string, unknown>,
67	): Record<string, unknown> {
68	  const undoPatch: Record<string, unknown> = {};
69	  for (const key of Object.keys(patch)) {
70	    undoPatch[key] = key in original ? original[key] : null;
71	  }
72	  return undoPatch;
73	}
74	
75	function applyMergePatch(
76	  original: Record<string, unknown>,
77	  patch: Record<string, unknown>,
78	): Record<string, unknown> {
79	  const patched: Record<string, unknown> = { ...original };
80	  for (const [key, value] of Object.entries(patch)) {
81	    if (value === null) {
82	      delete patched[key];
83	    } else {
84	      patched[key] = value;
85	    }
86	  }
87	  return patched;
88	}
89	
90	function sourceAccessError(err: unknown, sourcePath: string): string {
91	  const code = (err as NodeJS.ErrnoException).code;
92	  if (code === "ENOENT") return `Source not found: ${sourcePath}`;
93	  if (code === "EACCES" || code === "EPERM")
94	    return `Permission denied accessing source: ${sourcePath}`;
95	  const detail = err instanceof Error ? err.message : String(err);
96	  return `Failed to access source ${sourcePath}: ${detail}`;
97	}
98	
99	function detectCollisions(actions: DeployAction[]): PlanWarning[] {
100	  const seen = new Map<string, { skill: string; agent: AgentId }>();
101	  const warnings: PlanWarning[] = [];
102	  for (const action of actions) {
103	    const prev = seen.get(action.target);
104	    if (prev) {
105	      warnings.push({
106	        kind: "collision",
107	        message: `Skill "${action.skill}" for agent "${action.agent}" and skill "${prev.skill}" for agent "${prev.agent}" both resolve to the same target: ${action.target}`,
108	      });
109	    } else {
110	      seen.set(action.target, { skill: action.skill, agent: action.agent });
111	    }
112	  }
113	  return warnings;
114	}
115	
116	function detectAmbiguities(detectedAgents: AgentId[]): PlanWarning[] {
117	  const warnings: PlanWarning[] = [];
118	  if (
119	    detectedAgents.includes("gemini-cli") &&
120	    detectedAgents.includes("antigravity")
121	  ) {
122	    warnings.push({
123	      kind: "ambiguity",
124	      message:
125	        'Both "gemini-cli" and "antigravity" share the ~/.gemini/ base directory. antigravity skill support is implementation-only. Verify that deployed skill paths do not conflict.',
126	    });
127	  }
128	  return warnings;
129	}
130	
131	export async function planDeploy(
132	  manifest: Manifest,
133	  sourceDir: string,
134	  detectedAgents: AgentId[],
135	  home: string,
136	): Promise<{ actions: DeployAction[]; warnings: PlanWarning[] }> {
137	  const method = getDeployMethod();
138	  const actions: DeployAction[] = [];
139	  const resolvedSourceDir = path.resolve(sourceDir);
140	
141	  let realRoot: string;
