      command: "help",
      directory: "",
      dryRun: false,
      agents: null,
      verbose: false,
      debug: false,
    };
  }

  let command: "deploy" | "revert" = "deploy";
  let pos = positionals;
  if (pos[0] === "revert") {
    command = "revert";
    pos = pos.slice(1);
  }

  if (pos.length > 1) {
    throw new UserError("INVALID_ARGS", `Unexpected argument: ${pos[1]}`);
  }
  const rawDir = pos[0];
  if (!rawDir) {
    throw new UserError(
      "INVALID_ARGS",
      "Missing required <directory> argument",
    );
  }

  let agents: AgentId[] | null = null;
  if (typeof values.agents === "string") {
    const r = AgentListSchema.safeParse(values.agents);
    if (!r.success) {
      throw new UserError("INVALID_ARGS", r.error.issues[0].message);
    }
    agents = r.data;
  }

  return {
    command,
    directory: path.resolve(rawDir),
    dryRun: values["dry-run"] as boolean,
    agents,
    verbose: values.verbose as boolean,
    debug: values.debug as boolean,
  };
}

async function main(): Promise<number> {
  const options = parseCLI(process.argv);

  if (options.command === "help") {
    console.log(USAGE);
    return 0;
  }

  const manifest = await loadManifest(options.directory);
  const home = resolveHome();

  if (options.command === "deploy") {
    return runDeploy(options, manifest, home);
  }
  return runRevert(options, manifest, home);
}

async function runDeploy(
  options: CliOptions,
  manifest: Manifest,
  home: string,
): Promise<number> {
  let detectedAgents: AgentId[];
  if (options.agents) {
    detectedAgents = options.agents;
    if (options.verbose) {
      logger.info(`Using specified agents: ${detectedAgents.join(", ")}`);
    }
  } else {
    detectedAgents = await detectInstalledAgents(home);
    if (detectedAgents.length === 0) {
      logger.info("No supported AI agents detected on this system.");
      logger.info(
        `Install one of: ${AGENT_REGISTRY.map((a) => a.displayName).join(", ")}`,
      );
      return 0;
    }
    if (options.verbose) {
      logger.info(`Detected agents: ${detectedAgents.join(", ")}`);
    }
  }

  const preflightWarnings = await runPreflight(
    options,
    manifest,
    home,
    detectedAgents,
  );
  for (const w of preflightWarnings) {
    logger.warn("preflight", w.message);
  }

  const { actions, warnings: planWarnings } = await planDeploy(
    manifest,
    options.directory,
    detectedAgents,
    home,
  );
  for (const w of planWarnings) {
    logger.warn("plan", w.message);
  }
  if (actions.length === 0) {
    logger.info("No skills to deploy for detected agents.");
    return 0;
  }

  logger.info(
    `${dryRunPrefix(options.dryRun)}Deploying ${actions.length} skill(s):`,
  );
  const { succeeded, failed } = await executeDeploy(
    actions,
    options.dryRun,
    options.verbose,
    home,
  );

  logger.info("");
  if (failed.length > 0) {
    logger.info(`${succeeded} succeeded, ${failed.length} failed`);
    return 1;
  }
  logger.info(
    `${succeeded} skill(s) deployed${options.dryRun ? " (dry-run)" : ""}`,
  );
  return 0;
}

async function runRevert(
  options: CliOptions,
  manifest: Manifest,
  home: string,
): Promise<number> {
  const actions = options.agents
    ? planRevert(manifest, options.agents, home)
    : planRevertAll(manifest, home);
  if (actions.length === 0) {
    logger.info("No skills to revert.");
    return 0;
  }

  logger.info(
    `${dryRunPrefix(options.dryRun)}Reverting ${actions.length} skill(s):`,
  );
  const { succeeded, skipped, failed } = await executeRevert(
    actions,
    options.dryRun,
    options.verbose,
    home,
  );

  logger.info("");
  if (failed.length > 0) {
    const parts = [`${succeeded} removed`];
    if (skipped > 0) parts.push(`${skipped} skipped`);
    parts.push(`${failed.length} failed`);
    logger.info(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
    return 1;
  }
  const parts = [`${succeeded} removed`];
  if (skipped > 0) parts.push(`${skipped} skipped`);
  logger.info(`${parts.join(", ")}${options.dryRun ? " (dry-run)" : ""}`);
  return 0;
}

const USER_ERROR_EXIT: Record<ErrorCode, number> = {
  INVALID_ARGS: 2,
  MANIFEST_INVALID: 3,
  DEPLOY_FAILED: 1,
  RESOLVE_FAILED: 1,
};

const debugMode = process.argv.includes("--debug");

try {
  process.exit(await main());
} catch (err) {
  if (err instanceof UserError) {
    logger.error(`Error: ${err.message}`);
    if (debugMode) {
      logger.errorRaw(err);
    }
    process.exit(USER_ERROR_EXIT[err.code]);
  } else {
    logger.error("Unexpected error. Run with --debug for details.");
    if (debugMode) {
      logger.errorRaw(err);
    }
    process.exit(1);
  }
}

