import { lstat, readFile, rm, unlink, writeFile } from "node:fs/promises";
import path from "node:path";
import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
import { logger } from "../logger.ts";
import type {
  AgentId,
  Manifest,
  PlannedChange,
  RevertAction,
} from "../types.ts";
import type { ConfigPatchRegistryEntry } from "../schemas/registry.ts";
import { lookupDeployment, unregisterDeployment } from "./ownership.ts";
import { resolveAgentSkillPath } from "./resolve.ts";

function resolveTargetTemplate(template: string, home: string): string {
  const appdata = process.env.APPDATA ?? path.join(home, "AppData", "Roaming");
  const xdgRaw = process.env.XDG_CONFIG_HOME;
  const xdgConfig =
    xdgRaw && path.isAbsolute(xdgRaw) ? xdgRaw : path.join(home, ".config");
  return template
    .replace("{home}", home)
    .replace("{appdata}", appdata)
    .replace("{xdg_config}", xdgConfig);
}

export function planRevert(
  manifest: Manifest,
  detectedAgents: AgentId[],
  home: string,
): RevertAction[] {
  const actions: RevertAction[] = [];

  for (const skill of manifest.skills) {
    for (const agentId of skill.agents) {
      if (!detectedAgents.includes(agentId)) continue;

      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        target,
      });
    }
  }

  for (const fileEntry of manifest.files) {
    for (const agentId of fileEntry.agents) {
      if (!detectedAgents.includes(agentId)) continue;

      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveTargetTemplate(fileEntry.target, home);
      actions.push({
        kind: "file-write",
        skill: fileEntry.name,
        agent: agentId,
        target,
      });
    }
  }

  for (const configEntry of manifest.configs) {
    for (const agentId of configEntry.agents) {
      if (!detectedAgents.includes(agentId)) continue;

      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveTargetTemplate(configEntry.target, home);
      actions.push({
        kind: "config-patch",
        skill: configEntry.name,
        agent: agentId,
        target,
      });
    }
  }

  return actions;
}

export function planRevertAll(
  manifest: Manifest,
  home: string,
): RevertAction[] {
  const actions: RevertAction[] = [];

  for (const skill of manifest.skills) {
    for (const agentId of skill.agents) {
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveAgentSkillPath(agent, skill.name, home);
      actions.push({
        kind: "skill-dir",
        skill: skill.name,
        agent: agentId,
        target,
      });
    }
  }

  for (const fileEntry of manifest.files) {
    for (const agentId of fileEntry.agents) {
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveTargetTemplate(fileEntry.target, home);
      actions.push({
        kind: "file-write",
        skill: fileEntry.name,
        agent: agentId,
        target,
      });
    }
  }

  for (const configEntry of manifest.configs) {
    for (const agentId of configEntry.agents) {
      const agent = AGENT_REGISTRY_BY_ID[agentId];
      if (!agent) continue;

      const target = resolveTargetTemplate(configEntry.target, home);
      actions.push({
        kind: "config-patch",
        skill: configEntry.name,
        agent: agentId,
        target,
      });
    }
  }

  return actions;
}

type RevertOutcome =
  | { outcome: "ok" }
  | { outcome: "skip" }
  | { outcome: "fail"; error: string };

function recordOutcome(
  result: RevertOutcome,
  action: RevertAction,
  counts: { succeeded: number; skipped: number },
  failed: Array<{ action: RevertAction; error: string }>,
): void {
  if (result.outcome === "fail") {
    failed.push({ action, error: result.error });
  } else if (result.outcome === "skip") {
    counts.skipped++;
  } else {
    counts.succeeded++;
  }
}

async function readJsonConfig(
  filePath: string,
): Promise<Record<string, unknown>> {
  const rawContent = await readFile(filePath, "utf-8");
  let parsed: unknown;
  try {
    parsed = JSON.parse(rawContent);
  } catch {
    throw new Error(`Config file is not valid JSON: ${filePath}`);
  }
  if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
    throw new Error(`Config file is not a JSON object: ${filePath}`);
  }
  return parsed as Record<string, unknown>;
}

